property.value:

//MethodCall[
  @MethodName=('assertTrue', 'assertFalse', 'assertNotNull', 'assertNull', 'assertNotSame', 'assertSame', 'assertThat', 'assertEquals')]
  [not(ArgumentList//VariableAccess or ArgumentList//FieldAccess or ArgumentList//MethodCall or ArgumentList//ThisExpression)]
  [ancestor::ClassDeclaration[ExtendsList/ClassType[ends-with(@SimpleName, 'TestCase')]]]

rule.example:

import junit.framework.*;
public class Foo extends TestCase {
 public void test1() {
     assertTrue( true );    // oops, does not test anything useful!
     assertEquals( 0, 0 );  // oops, does not test anything useful!
 }
}

property.value:

//MethodCall[
  @MethodName=('assertTrue', 'assertFalse', 'assertNotNull', 'assertNull', 'assertNotSame', 'assertSame', 'assertThat', 'assertEquals')]
  [not(ArgumentList//VariableAccess or ArgumentList//FieldAccess or ArgumentList//MethodCall or ArgumentList//ThisExpression)]
  [ancestor::MethodDeclaration[ModifierList/Annotation[ends-with(@SimpleName, 'Test')]]]

rule.example:

import org.junit.*;
public class Foo {
 @Test
 public void test1() {
     assertTrue( true );    // oops, does not test anything useful!
     assertEquals( 0, 0 );  // oops, does not test anything useful!
 }
}


import junit.framework.*;
public class Foo extends TestCase {
 public void test1() {
     assertThat( "any value" );    // oops, does not test anything useful!
 }
}


public class FooClass
{
    public void foo(int arg0, String arg1)
    {
    }
}


